def clock_sync(M, clocks, queries):
    from math import gcd

    def ext_gcd(a, b):
        if a == 0:
            return b, 0, 1
        g, x, y = ext_gcd(b % a, a)
        return g, y - (b // a) * x, x

    def mod_inv(a, m):
        if m == 1:
            return 0
        g, x, _ = ext_gcd(a % m, m)
        if g != 1:
            return None
        return x % m

    def solve_congruence(c, d, mod):
        c, d = c % mod, d % mod
        if c == 0:
            return (0, 1) if d == 0 else None
        g = gcd(c, mod)
        if d % g != 0:
            return None
        c2, d2, m2 = c // g, d // g, mod // g
        return (d2 * mod_inv(c2, m2) % m2, m2)

    def combine(a1, m1, a2, m2):
        g = gcd(m1, m2)
        if (a2 - a1) % g != 0:
            return None
        lcm_val = m1 // g * m2
        m2g = m2 // g
        k = ((a2 - a1) // g * mod_inv(m1 // g, m2g)) % m2g
        return ((a1 + m1 * k) % lcm_val, lcm_val)

    results = []
    for query in queries:
        if len(query) <= 1:
            results.append(0)
            continue
        ref_o, ref_r = clocks[query[0]]
        a, m = 0, 1
        ok = True
        for idx in query[1:]:
            o_i, r_i = clocks[idx]
            res = solve_congruence((ref_r - r_i) % M, (o_i - ref_o) % M, M)
            if res is None:
                ok = False
                break
            comb = combine(a, m, res[0], res[1])
            if comb is None:
                ok = False
                break
            a, m = comb
        results.append(a % m if ok else -1)
    return results
